  it("CustomDimension", () => {
    const avg: DerivedMetricInfo = {
      id: "id-avg",
      telemetryType: "Request",
      filterGroups: [{ filters: [] }],
      projection: "CustomDimensions.property",
      aggregation: "Avg",
      backEndAggregation: "Avg",
    };

    const min: DerivedMetricInfo = {
      id: "id-min",
      telemetryType: "Request",
      filterGroups: [{ filters: [] }],
      projection: "CustomDimensions.property",
